transform_js:
const categories = []; const values = [];
rawData.rows.forEach(r => {
  categories.push(r.category);
  values.push(r.value);
});
transformedData = { categories, values };

echarts_js:
const symbolPath = 'path://M0,10 L10,10 L5,0 Z'; // Simple triangle/mountain shape for demo
option = {
  title: {
    text: 'Waste Volume (Pictorial Bar)',
    left: 'center'
  },
  tooltip: { trigger: 'axis', axisPointer: { type: 'none' } },
  xAxis: {
    data: transformedData.categories,
    axisTick: { show: false },
    axisLine: { show: false },
    axisLabel: { color: '#e54035' }
  },
  yAxis: {
    splitLine: { show: false },
    axisTick: { show: false },
    axisLine: { show: false },
    axisLabel: { show: false }
  },
  color: ['#e54035'],
  series: [
    {
      name: 'Volume',
      type: 'pictorialBar',
      barCategoryGap: '-130%',
      symbol: symbolPath,
      itemStyle: {
        normal: {
          opacity: 0.5
        },
        emphasis: {
          opacity: 1
        }
      },
      data: transformedData.values,
      z: 10
    }
  ]
};
